import { execSync } from 'child_process';
import * as fs from 'fs';
import * as path from 'path';
import { addMessage, getHistory } from './memory';

function loadEnv(): Record<string, string> {
    const envPath = path.resolve(process.cwd(), '../.env');
    let vars: Record<string, string> = { ...process.env } as Record<string, string>;

    try {
        if (fs.existsSync(envPath)) {
            const content = fs.readFileSync(envPath, 'utf-8');
            content.split('\n').forEach(line => {
                const trimmed = line.trim();
                if (!trimmed || trimmed.startsWith('#')) return;
                const eqIdx = trimmed.indexOf('=');
                if (eqIdx !== -1) {
                    let val = trimmed.substring(eqIdx + 1).trim();
                    if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
                        val = val.slice(1, -1);
                    }
                    vars[trimmed.substring(0, eqIdx).trim()] = val;
                }
            });
        }
    } catch (e: any) {
        fs.appendFileSync('debug-log.txt', `Env Load Error: ${e.message}\n`);
    }
    return vars;
}

function curlCall(apiUrl: string, apiKey: string, proxyUrl: string | null, payload: any) {
    const isWindows = process.platform === 'win32';
    const curlCmd = isWindows ? 'curl.exe' : 'curl';
    const tmpFile = isWindows ? path.join(process.cwd(), `tmp-${Date.now()}.json`) : `/tmp/p-${Date.now()}.json`;

    try {
        fs.writeFileSync(tmpFile, JSON.stringify(payload));
        let cmd = `${curlCmd} -s -X POST "${apiUrl}" -H "Content-Type: application/json"`;
        if (apiKey) cmd += ` -H "Authorization: Bearer ${apiKey}"`;
        if (proxyUrl) cmd += ` -x "${proxyUrl}"`;
        cmd += ` -d "@${tmpFile}"`;

        const res = execSync(cmd, { encoding: 'utf-8' });
        if (fs.existsSync(tmpFile)) fs.unlinkSync(tmpFile);
        return JSON.parse(res);
    } catch (e: any) {
        if (fs.existsSync(tmpFile)) try { fs.unlinkSync(tmpFile); } catch (err) { }
        fs.appendFileSync('debug-log.txt', `CURL Error: ${e.message}\n`);
        return null;
    }
}

export async function processAiMessage(userMessage: string) {
    const env = loadEnv();
    let history: any[] = [];

    fs.appendFileSync('debug-log.txt', `Processing: ${userMessage}\n`);

    try {
        history = await getHistory(15);
    } catch (e: any) {
        fs.appendFileSync('debug-log.txt', `History Fetch Error: ${e.message}\n`);
    }

    const fullMessages = [...history, { role: 'user', content: userMessage }];

    const providers: any[] = [
        { id: "Mistral", apiKey: "gzGgFDnH44vj9lVS64TP0xhlZrr2QUdB", url: "https://api.mistral.ai/v1/chat/completions", model: "mistral-small-latest", type: "openai" },
        { id: "Moonshot", apiKey: "sk-Ndtm154XrJCeaxDLpSVIXZdsRTebHFX0dfDXSPrPr75LLG69", url: "https://api.moonshot.cn/v1/chat/completions", model: "moonshot-v1-8k", type: "openai" },
        { id: "Cerebras", apiKey: env.CEREBRAS_API_KEY, url: "https://api.cerebras.ai/v1/chat/completions", model: "llama3.3-70b", type: "openai" }
    ];

    const geminiKeys = [
        env.GEMINI_KEY_8, env.GEMINI_KEY_1, env.GEMINI_KEY_2,
        env.GEMINI_KEY_3, env.GEMINI_KEY_4, env.GEMINI_KEY_5,
        env.GEMINI_KEY_6, env.GEMINI_KEY_7
    ].filter(k => k && k !== "SUTITUYE POR EL TUYO" && !k.includes("..."));

    const proxies = [
        env.LAUNCH_URL_11435, env.LAUNCH_URL_11436, env.LAUNCH_URL_11437,
        env.LAUNCH_URL_11438, env.LAUNCH_URL_11439
    ].filter(p => p);

    geminiKeys.forEach((key, i) => {
        providers.push({
            id: `Gemini-${i + 1}`,
            apiKey: key,
            url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash-8b:generateContent?key=${key}`,
            proxy: proxies[i % (proxies.length || 1)] || null,
            model: "gemini-1.5-flash-8b",
            type: "gemini_native"
        });
    });

    for (const p of providers) {
        if (!p.apiKey && !p.proxy) continue;
        try {
            fs.appendFileSync('debug-log.txt', `Trying: ${p.id}\n`);
            const payload = p.type === 'gemini_native' ? {
                contents: fullMessages.map((m: any) => ({
                    role: m.role === 'assistant' ? 'model' : 'user',
                    parts: [{ text: m.content }]
                }))
            } : {
                model: p.model,
                messages: fullMessages,
                max_tokens: 1024
            };

            const data = curlCall(p.url, p.type === 'gemini_native' ? "" : p.apiKey, p.proxy, payload);
            if (!data) continue;

            let reply = "";
            if (p.type === 'gemini_native') reply = data.candidates?.[0]?.content?.parts?.[0]?.text;
            else reply = data.choices?.[0]?.message?.content;

            if (reply) {
                fs.appendFileSync('debug-log.txt', `Success: ${p.id}\n`);
                try {
                    await addMessage('user', userMessage);
                    await addMessage('assistant', reply);
                } catch (dbErr: any) {
                    fs.appendFileSync('debug-log.txt', `DB Save Error: ${dbErr.message}\n`);
                }
                return { reply, engine: p.id };
            }
        } catch (e: any) {
            fs.appendFileSync('debug-log.txt', `${p.id} Error: ${e.message}\n`);
        }
    }
    fs.appendFileSync('debug-log.txt', `All providers failed.\n`);
    return { reply: "❌ No Engine responded. Check proxies and .env keys.", engine: "Offline" };
}
