import { NextRequest, NextResponse } from 'next/server';
import { processAiMessage } from '@/lib/ai_logic';

export async function POST(req: NextRequest) {
    try {
        const { messages } = await req.json();
        if (!messages || messages.length === 0) {
            return NextResponse.json({ reply: "No messages provided", engine: "None" }, { status: 400 });
        }
        const lastMsg = messages[messages.length - 1].content;
        const result = await processAiMessage(lastMsg);
        return NextResponse.json(result);
    } catch (e: any) {
        console.error('CHAT_API_ERROR:', e.message || e);
        return NextResponse.json({
            reply: "❌ Server Error: " + (e.message || "Unknown error"),
            engine: "Offline"
        }, { status: 500 });
    }
}

